async function main({ params, context }) {
  // 从开始节点获取上传的文件
  const file = params.input_file;
  // 兼容结构：可能是 { url, name, type } 也可能直接是字符串路径
  const fileName = (file && (file.name || file.filename)) || (typeof file === 'string' ? file.split(/[\\\\/]/).pop() : '');
  const mimeType = (file && file.type) || '';
  const ext = (fileName || '').toLowerCase().split('.').pop();

  const videoExts = ['mp4', 'mov', 'mkv', 'avi', 'flv', 'wmv', 'webm', 'm4v', 'mpeg', 'mpg', 'ts', '3gp'];
  const audioExts = ['mp3', 'wav', 'aac', 'flac', 'ogg', 'm4a', 'wma', 'opus', 'amr', 'aiff', 'ac3'];

  let fileType = 'other';
  if (mimeType.startsWith('video/') || videoExts.includes(ext)) {
    fileType = 'video';
  } else if (mimeType.startsWith('audio/') || audioExts.includes(ext)) {
    fileType = 'audio';
  }

  return {
    file_type: fileType,
    file_name: fileName,
    file_ext: ext,
    mime_type: mimeType,
    original_file: file
  };
}

